Below is a **single, self‑contained** description of the OCaml‑side interface (`blocksci.mli`) together with the C/C++ stubs that implement it (`blocksci_stubs.c`).  
The design follows the pattern used by data‑frame libraries (Polars, pandas, …): the user supplies an OCaml callback that is invoked for **every block** while the native iterator walks the collection.  

The hot path is kept **allocation‑free** – we allocate a single OCaml custom value that merely points at the current native `Block*`.  The value is only valid for the duration of the callback call; if the user wants to keep a block around they must copy the fields they need (via the accessor functions).

---

## 1. OCaml interface – `blocksci.mli`

```ocaml
(** {1 BlockSci OCaml bindings} *)

(** Abstract handle to a native Block object.  The value is only valid
    for the duration of the callback passed to {!walk_blocks}. *)
type block

(** {2 Accessors – read‑only view of a block} *)

val height    : block -> int
(** [height b] is the block height (0‑based). *)

val hash      : block -> string
(** [hash b] is the 32‑byte block hash as a binary string. *)

val timestamp : block -> int64
(** [timestamp b] is the Unix epoch time of the block. *)

val tx_count  : block -> int
(** [tx_count b] is the number of transactions in the block. *)

(** {2 Iteration} *)

val walk_blocks : (block -> unit) -> unit
(** [walk_blocks f] walks the whole blockchain (≈ 800 M blocks) and calls
    [f b] for each block.  The callback runs in the same thread as the
    iterator; if it raises an exception the walk stops and the exception
    is propagated to the caller.  The [block] argument is a temporary
    handle that becomes invalid as soon as the callback returns – if the
    user wants to retain data they must copy it with the accessor
    functions. *)

(** {2 Convenience} *)

val block_count : unit -> int64
(** Total number of blocks in the loaded chain. *)

val init : string -> unit
(** Initialise the library with the path to the BlockSci database.
    Must be called once before any other function. *)
```

*All functions are pure from the OCaml point of view – the only side‑effect
is the native iteration performed by {!walk_blocks}.*

---

## 2. C/C++ stub – `blocksci_stubs.c`

> **Compilation tip**  
> ```
> ocamlopt -c -ccopt "-std=c++17 -I$(OCAMLHOME)/caml" blocksci_stubs.c
> ocamlopt -a -o libblocksci.cmxa blocksci_stubs.o -ccopt "-lstdc++"
> ```
> (Replace `$(OCAMLHOME)` with the path to your OCaml installation.)

```c
/* blocksci_stubs.c   –  C/C++ glue for the OCaml BlockSci bindings
 *
 *  The native BlockSci library is assumed to expose (pseudo‑code):
 *
 *      class Block {
 *        public:
 *          uint32_t height;
 *          std::array<unsigned char,32> hash;
 *          int64_t   timestamp;
 *          uint32_t  tx_count;
 *      };
 *
 *      class BlockIterator {
 *        public:
 *          BlockIterator begin() const;
 *          BlockIterator end() const;
 *          Block* operator*() const;
 *          BlockIterator& operator++();
 *          bool operator!=(const BlockIterator&) const;
 *      };
 *
 *      BlockIterator blocks_begin();
 *      BlockIterator blocks_end();
 *      uint64_t block_count();
 *      void init(const std::string& db_path);
 *
 *  The real library may have a different API – adapt the wrappers below
 *  accordingly.
 */

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>

#include <cstdint>
#include <string>
#include <vector>
#include <cstring>

/* ------------------------------------------------------------------ */
/*  Forward declarations of the (fictional) BlockSci C++ API           */
/* ------------------------------------------------------------------ */
extern "C" {
    /* The real BlockSci library ships a C‑compatible header; we just
       declare the needed symbols here to keep the example self‑contained. */
    void bsci_init(const char* db_path);
    uint64_t bsci_block_count(void);
    /* Opaque iterator type – we expose it as a C++ class. */
    struct Block;
    struct BlockIterator;
    BlockIterator* bsci_blocks_begin(void);
    BlockIterator* bsci_blocks_end(void);
    void bsci_iterator_delete(BlockIterator* it);
    bool bsci_iterator_eq(const BlockIterator* a, const BlockIterator* b);
    void bsci_iterator_next(BlockIterator* it);
    Block* bsci_iterator_deref(const BlockIterator* it);
}

/* ------------------------------------------------------------------ */
/*  OCaml custom block – a thin wrapper around a native Block*        */
/* ------------------------------------------------------------------ */
static struct custom_operations block_ops = {
    "Blocksci.block",
    custom_finalize_default,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* Helper: turn a native Block* into an OCaml custom value.
   We reuse the same OCaml value for every iteration (see walk_blocks). */
static inline value caml_wrap_block(Block* b) {
    CAMLparam0();
    /* The custom value was allocated once and lives for the whole walk.
       Here we only update the stored pointer. */
    static value v_block = Val_unit;
    if (v_block == Val_unit) {
        v_block = caml_alloc_custom(&block_ops, sizeof(Block*), 0, 1);
    }
    Block** slot = (Block**)Data_custom_val(v_block);
    *slot = b;
    CAMLreturn(v_block);
}

/* ------------------------------------------------------------------ */
/*  Accessor implementations                                            */
/* ------------------------------------------------------------------ */
CAMLprim value caml_block_height(value v_block) {
    CAMLparam1(v_block);
    Block* b = *(Block**)Data_custom_val(v_block);
    CAMLreturn(Val_int((int)b->height));
}

CAMLprim value caml_block_hash(value v_block) {
    CAMLparam1(v_block);
    CAMLlocal1(v_str);
    Block* b = *(Block**)Data_custom_val(v_block);
    /* hash is 32 raw bytes – we expose it as a binary OCaml string. */
    v_str = caml_alloc_string(32);
    memcpy(String_val(v_str), b->hash.data(), 32);
    CAMLreturn(v_str);
}

CAMLprim value caml_block_timestamp(value v_block) {
    CAMLparam1(v_block);
    Block* b = *(Block**)Data_custom_val(v_block);
    CAMLreturn(caml_copy_int64(b->timestamp));
}

CAMLprim value caml_block_tx_count(value v_block) {
    CAMLparam1(v_block);
    Block* b = *(Block**)Data_custom_val(v_block);
    CAMLreturn(Val_int((int)b->tx_count));
}

/* ------------------------------------------------------------------ */
/*  Core iteration primitive                                            */
/* ------------------------------------------------------------------ */
CAMLprim value caml_walk_blocks(value v_fun) {
    CAMLparam1(v_fun);
    CAMLlocal1(v_block);
    /* --------------------------------------------------------------
       The iterator is completely native; we only allocate a *single*
       OCaml custom value that we update on each step.  This keeps the
       hot loop allocation‑free.
       -------------------------------------------------------------- */
    BlockIterator* it  = bsci_blocks_begin();   /* start   */
    BlockIterator* end = bsci_blocks_end();     /* finish  */

    for ( ; !bsci_iterator_eq(it, end); bsci_iterator_next(it) ) {
        Block* native = bsci_iterator_deref(it);
        v_block = caml_wrap_block(native);      /* update pointer */
        value result = caml_callback_exn(v_fun, v_block);
        if (Is_exception_result(result)) {
            /* Propagate the OCaml exception out of the loop. */
            bsci_iterator_delete(it);
            bsci_iterator_delete(end);
            caml_raise(result);
        }
    }

    bsci_iterator_delete(it);
    bsci_iterator_delete(end);
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------ */
/*  Miscellaneous helpers                                                */
/* ------------------------------------------------------------------ */
CAMLprim value caml_block_count(value unit) {
    (void)unit;
    return caml_copy_int64((int64_t)bsci_block_count());
}

CAMLprim value caml_init(value v_path) {
    CAMLparam1(v_path);
    const char* path = String_val(v_path);
    bsci_init(path);
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------ */
/*  Register the primitives with OCaml                                    */
/* ------------------------------------------------------------------ */
static const struct caml_named_value caml_named_values[] = {
    { "Blocksci.block_height",    caml_block_height },
    { "Blocksci.block_hash",      caml_block_hash },
    { "Blocksci.block_timestamp", caml_block_timestamp },
    { "Blocksci.block_tx_count",  caml_block_tx_count },
    { "Blocksci.walk_blocks",     caml_walk_blocks },
    { "Blocksci.block_count",     caml_block_count },
    { "Blocksci.init",            caml_init },
    { NULL, NULL }
};

CAMLprim value caml_register_prims(value unit) {
    (void)unit;
    for (const struct caml_named_value* p = caml_named_values; p->name != NULL; ++p) {
        caml_register_named_value(p->name, p->fn);
    }
    return Val_unit;
}
```

### How the pieces fit together

* **OCaml side** (`blocksci.mli`) declares an abstract type `block` and
  accessor functions.  The only entry point that does work is `walk_blocks`.

* **C stub** (`blocksci_stubs.c`) implements:
  * `caml_init` – initialise the native library (called once from OCaml).
  * `caml_block_count` – a cheap query.
  * The **custom block** wrapper (`block_ops`) that holds a `Block*`.
  * Accessors (`caml_block_*`) that read fields from the native `Block`.
  * `caml_walk_blocks` – the hot loop.  It:
      1. Creates a *single* OCaml custom value that points at the current native block.
      2. Calls the user‑supplied OCaml closure via `caml_callback_exn`.
      3. If the closure raises, the exception is re‑raised and iteration stops.
      4. No per‑iteration allocation (apart from the occasional GC
         root handling) – this is comparable to the approach used by
         Polars/pandas where the Python callback receives a view of the row.

* The `caml_register_prims` function is optional – it lets you
  `Dl.dlopen` the shared library and retrieve the primitives by name,
  which matches the pattern used by many OCaml‑C bindings.  You can also
  expose the functions directly via `external` declarations in a
  companion `.ml` file.

---

## 3. Example OCaml usage

```ocaml
(* blocksci.ml – thin wrapper around the C primitives *)
external init          : string -> unit = "Blocksci.init"
external block_count  : unit -> int64 = "Blocksci.block_count"
external walk_blocks   : (block -> unit) -> unit = "Blocksci.walk_blocks"

external height    : block -> int    = "Blocksci.block_height"
external hash      : block -> string = "Blocksci.block_hash"
external timestamp : block -> int64 = "Blocksci.block_timestamp"
external tx_count  : block -> int    = "Blocksci.block_tx_count"

let () =
  init "/path/to/blocksci/db";
  Printf.printf "Chain has %Ld blocks\n%!" (block_count ());
  walk_blocks (fun blk ->
      (* Very cheap work – just a few integer reads. *)
      if height blk mod 1_000_000 = 0 then
        Printf.printf "Block %d – %Ld txs – %s\n%!"
          (height blk) (tx_count blk) (hash blk |> Hex.of_string)
    )
```

The example shows a realistic use‑case: printing a line every millionth
block.  The per‑block cost is essentially the cost of dereferencing a
pointer and a few integer loads – the same order of magnitude as the
native C++ iterator itself.

---

### Summary of design choices

| Concern | Solution |
|---------|----------|
| **Zero allocation per block** | Re‑use a single OCaml custom value (`caml_wrap_block`). |
| **Safety** | Document that the `block` value is only valid during the callback; if the user stores it they must copy the fields they need. |
| **Exception handling** | `caml_callback_exn` + `Is_exception_result` → propagate the OCaml exception out of the loop. |
| **Performance** | The hot loop lives entirely in C++ (`for` over native iterator).  Only a tiny amount of OCaml‑C marshaling (pointer update + call) per iteration. |
| **Ease of use** | Pure OCaml API (`walk_blocks`) that feels like a higher‑order function, exactly like data‑frame row‑wise APIs. |
| **Extensibility** | Additional accessors can be added without touching the iteration core. |
| **Thread model** | Single‑threaded; if you need parallelism you can split the range of heights into chunks and run several `walk_blocks` in parallel (each with its own iterator). |

With this binding the OCaml user can write idiomatic, row‑wise
analytics code while the underlying C++ engine does the heavy lifting
with essentially no overhead.
